import React, {useState} from 'react';

import InputArea from './components/input/input-area';
import TextDisplay from './components/text/text-display';

import getText from './services/get-text';

const App = () => {
  const [texts, setTexts] = useState([]);

  async function textHandler(id) {
    const text = await getText(id);

    await setTexts((prev) => {
      return [...prev, {line: text[0].text, id: id}]
    });
  }

  const submitIndexes = (array) => {
    setTexts([]);
    array.forEach((id) => {
      textHandler(id);
    })
  };

  return (
    <>
      <InputArea submitIndexes = {submitIndexes}/>
      <TextDisplay texts = {texts}/>
    </>
  );
};

export default App;